#!/usr/bin/env python3
import base64, os, sys
PAYLOAD = ""
dest = os.path.join("screens", "KnockingSessionScreen.js")
if not os.path.isdir("screens"):
    sys.exit("Run from BatKnock root folder")
with open(dest, "wb") as f:
    f.write(base64.b64decode(PAYLOAD))
print("Done — now run: npx expo start --clear --lan")
